"use strict";(self.webpackChunkdocs=self.webpackChunkdocs||[]).push([[40680],{23138:(e,i,n)=>{n.r(i),n.d(i,{data:()=>s});const s={key:"v-712ac73e",path:"/C#/%E8%87%AA%E5%AE%9A%E4%B9%89%E6%8E%A7%E4%BB%B6/15.%E7%B1%BB%E5%9E%8B%E7%BC%96%E8%BE%91%E5%99%A8.html",title:"自定义控件(十五)-类型编辑器",lang:"zh-CN",frontmatter:{},excerpt:"",headers:[],git:{updatedTime:1655779244e3,contributors:[{name:"panzhiyue",email:"30484534+panzhiyue@users.noreply.github.com",commits:1}]},filePathRelative:"C#/自定义控件/15.类型编辑器.md"}},72367:(e,i,n)=>{n.r(i),n.d(i,{default:()=>t});const s=(0,n(57293).uE)('<h1 id="自定义控件-十五-类型编辑器" tabindex="-1"><a class="header-anchor" href="#自定义控件-十五-类型编辑器" aria-hidden="true">#</a> 自定义控件(十五)-类型编辑器</h1><p>类型编辑器（UITypeEditor）非常常见，如Image控件的ImageUrl属性就带有类型编辑器，如图所示</p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210856892.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"><img src="https://gitee.com/panzhiyue/picgo-image/raw/master/img/202111010926476.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p>自定义控件要想让属性拥有类型编辑器，需要通过EditorAttribute关联到控件的属性上。</p><p>1.常见的编辑器有</p><ul><li>编辑时间的DateTimeEditor</li><li>编辑颜色的ColorEditor</li><li>编辑字体的FontEditor</li><li>用于数据库连接字符串的ConnectionStringEditor</li><li>等等</li></ul><p>2.编辑器的显示方式由UITypeEditor.GetEditStyle()觉得，DropDown(下拉框),Modal(模态窗口),None</p><p>3.用一个小图标表示属性的值，GetPaintValueSupported()返回true,重写PaintValue()提供绘制小图标的逻辑</p><p>4.EditValue()负责组织编辑属性值的过程</p><p>下面我们给Label添加Time属性，并显示出来，代码如下</p><div class="language-csharp ext-cs line-numbers-mode"><pre class="language-csharp"><code>using System;\nusing System.ComponentModel;\nusing System.ComponentModel.Design;\nusing System.Drawing.Design;\nusing System.Web.UI.WebControls;\n\nnamespace PZY.BLL.Web.lx._6sjq\n{\n    [DefaultProperty(&quot;Time&quot;)]\n    public class LabelEditor:Label\n    {\n        [Editor(typeof(DateTimeEditor),typeof(UITypeEditor))]\n        public  DateTime Time\n        {\n            get\n            {\n                if (ViewState[&quot;Time&quot;] != null)\n                {\n                    return (DateTime)ViewState[&quot;Time&quot;];\n                }\n                return DateTime.Now;\n            }\n            set { ViewState[&quot;Time&quot;] = value; }\n        }\n        protected override void AddAttributesToRender(System.Web.UI.HtmlTextWriter writer)\n        {\n            base.AddAttributesToRender(writer);\n            this.Text = this.Time.ToString();\n        }\n    }\n}\n</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><p><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p><p><img src="https://pzy-images.oss-cn-hangzhou.aliyuncs.com/img/202206210856882.png" alt="img"><img src="data:image/gif;base64,R0lGODlhAQABAPABAP///wAAACH5BAEKAAAALAAAAAABAAEAAAICRAEAOw==" alt="点击并拖拽以移动"></p>',13),l={},t=(0,n(63243).Z)(l,[["render",function(e,i){return s}]])},63243:(e,i)=>{i.Z=(e,i)=>{const n=e.__vccOpts||e;for(const[e,s]of i)n[e]=s;return n}}}]);